## 1. multiAgentService.ts 核心接口设计

```typescript
// src/services/multiAgentService.ts

/**
 * 4种校验Agent类型
 */
export type AgentType = 'power-contradiction' | 'timeline-contradiction' | 'character-consistency' | 'causality-trace';

/**
 * 单个Agent校验结果
 */
export interface AgentResult {
  type: AgentType;
  status: 'success' | 'error';
  contradictions: Contradiction[];
  summary: string; // 100字以内
}

/**
 * 矛盾条目
 */
export interface Contradiction {
  location: string; // 章节/段落位置
  description: string;
  severity: 'low' | 'medium' | 'high';
}

/**
 * 核心接口
 */

// 1. 触发并行校验（4种子校验同时跑）
function runLogicalValidation(novelData: NovelData): Promise<AgentResult[]>;

// 2. 获取校验进度
function getValidationProgress(taskId: string): ValidationProgress;

// 3. 汇总报告生成
function generateReport(results: AgentResult[]): ContradictionReport;

// 4. 取消正在进行的校验
function cancelValidation(taskId: string): void;

// 5. 重新跑单个校验（用于修复后复验）
function revalidateAgent(novelData: NovelData, agentType: AgentType): Promise<AgentResult>;
```

