## 2. 调度器汇总逻辑（关键代码片段）

```typescript
// src/services/multiAgentService.ts

import { callDeepSeek } from './aiService';

const AGENT_PROMPTS: Record<AgentType, string> = {
  'power-contradiction': '校验战力体系矛盾（如主角前期能打后期却打不过小怪）',
  'timeline-contradiction': '校验时间线矛盾（如季节交替错误、节日时间冲突）',
  'character-consistency': '校验人物行为一致性（如性格突变、忘记已发生的事）',
  'causality-trace': '校验因果链追溯（如缺少铺垫直接开挂）',
};

export async function runLogicalValidation(novelData: NovelData): Promise<AgentResult[]> {
  const taskId = `val_${Date.now()}`;
  const agentTypes: AgentType[] = [
    'power-contradiction',
    'timeline-contradiction', 
    'character-consistency',
    'causality-trace'
  ];

  // ✅ Promise.all 并行调用 4 个 Agent
  const results = await Promise.all(
    agentTypes.map(type => runSingleAgent(novelData, type))
  );

  // ✅ 调度器汇总：生成统一报告
  const report = generateReport(results);
  console.log(`[${taskId}] 校验完成，发现 ${report.totalContradictions} 处矛盾`);

  return results;
}

async function runSingleAgent(novelData: NovelData, type: AgentType): Promise<AgentResult> {
  try {
    const prompt = buildPrompt(AGENT_PROMPTS[type], novelData);
    const response = await callDeepSeek(prompt, { 
      model: 'deepseek-chat',
      max_tokens: 500 
    });

    return parseAgentResult(type, response);
  } catch (error) {
    return {
      type,
      status: 'error',
      contradictions: [],
      summary: `校验失败: ${error.message}`
    };
  }
}

export function generateReport(results: AgentResult[]): ContradictionReport {
  const allContradictions = results.flatMap(r => r.contradictions);

  return {
    taskId: `val_${Date.now()}`,
    timestamp: new Date().toISOString(),
    totalChecks: results.length,
    totalContradictions: allContradictions.length,
    bySeverity: {
      high: allContradictions.filter(c => c.severity === 'high').length,
      medium: allContradictions.filter(c => c.severity === 'medium').length,
      low: allContradictions.filter(c => c.severity === 'low').length,
    },
    details: results,
    summary: allContradictions.length === 0 
      ? '未检测到矛盾' 
      : `发现 ${allContradictions.length} 处矛盾，请查看详情`
  };
}
```

