## 3. aiService.ts 需要新增的内容

```typescript
// src/services/aiService.ts 新增

/**
 * 调用 DeepSeek API（流式）
 */
export async function callDeepSeek(
  prompt: string, 
  options: {
    model?: string;
    max_tokens?: number;
    temperature?: number;
  } = {}
): Promise<string> {
  const API_KEY = process.env.DEEPSEEK_API_KEY;
  const API_URL = 'https://api.deepseek.com/v1/chat/completions';

  const response = await fetch(API_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${API_KEY}`
    },
    body: JSON.stringify({
      model: options.model || 'deepseek-chat',
      messages: [{ role: 'user', content: prompt }],
      max_tokens: options.max_tokens || 500,
      temperature: options.temperature || 0.7
    })
  });

  if (!response.ok) {
    throw new Error(`DeepSeek API error: ${response.status}`);
  }

  const data = await response.json();
  return data.choices[0].message.content;
}

/**
 * 构建校验 Prompt（可在 aiService 或 multiAgentService 中）
 */
export function buildValidationPrompt(
  agentType: AgentType, 
  novelData: NovelData
): string {
  return `
你是小说逻辑校验专家。请分析以下小说内容，检测【${agentType}】相关矛盾。

要求输出 JSON 格式（100字以内总结）：
{
  "contradictions": [
    { "location": "第X章", "description": "矛盾描述", "severity": "high/medium/low" }
  ],
  "summary": "总结（100字以内）"
}

小说内容：
${novelData.content}
`;
}
```

